710	//                       proxy rawText = "<system-reminder>\nThe following skills are available for use with the Skill tool:\n\n{content}\n</system-reminder>\n"
711	//   local_command_history → proxy rawText = 原始 <local-command-*> / <bash-*> 标签文本，无额外包装
712	//   其他 category     → 直接返回原始文本（不包装）
713	//
714	// TODO(skill-listing-hash-方案B): 当前方案在内容中带有 skill 描述变化时 hash 可命中；
715	// 但若 header 文本随版本变化，需同步更新此处。方案B（attribution 层区分子类型 + M3.5 ruleId 匹配）
716	// 更鲁棒，不依赖固定 header 文本。参见 mutationToSegment 里的 TODO 注释。
717	// resolvePlaceholders：把 contentPattern 里的 {key} 占位符替换为 attribution notes 里的值。
718	// attribution notes 格式：["key=value", "key2=value2", ...]
719	// 占位符格式：{key}（与 rule-registry 注释约定一致）
720	// 替换后若仍有未解析的 {placeholder}，返回 null（防止用带占位符的字符串算 hash）。
721	function resolvePlaceholders(pattern: string, notes: string[]): string | null {
722	  const kvMap = new Map<string, string>();
723	  for (const note of notes) {
724	    const eq = note.indexOf("=");
725	    if (eq < 0) continue;
726	    kvMap.set(note.slice(0, eq), note.slice(eq + 1));
727	  }
728	  let result = pattern;
729	  for (const [k, v] of kvMap) {
730	    result = result.replaceAll(`{${k}}`, v);
731	  }
732	  // 若仍有未替换的占位符，返回 null
733	  if (/\{[a-zA-Z_]+\}/.test(result)) return null;
734	  return result;

